<?php
session_start();
include "db.php"; // Database connection file

if ($_SERVER["REQUEST_METHOD"] == "POST") {
    
    // Form se data le kar safe karna
    $full_name = trim($_POST['full_name']);
    $email     = trim($_POST['email']);
    $phone     = trim($_POST['phone']);
    $message   = trim($_POST['message']);

    // Prepared statement taake SQL Injection na ho ske
    $stmt = $conn->prepare("INSERT INTO contact_messages (full_name, email, phone, message) VALUES (?, ?, ?, ?)");
    $stmt->bind_param("ssss", $full_name, $email, $phone, $message);

    if ($stmt->execute()) {
        // Message save hone ke baad wapis contact page par success alert ke sath bhej do
        header("Location: ContactUs.php?status=success");
        exit();
    } else {
        echo "Error: " . $conn->error;
    }

    $stmt->close();
    $conn->close();
} else {
    // Agar koi direct access karne ki koshish kare to wapis bhej do
    header("Location: ContactUs.php");
    exit();
}
?>